import React from 'react';
import { View } from 'react-native';
import SQLite from 'expo-sqlite';

const db = SQLite.openDatabase({
  name: 'todos.db',
});

interface TodoItem {
  id: number;
  title: string;
}

class TodoList extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
      todos: [],
    };
  }

  async componentDidMount() {
    const todos = await db.all("SELECT * FROM todos");
    this.setState({ todos });
  }

  async addTodo(title: string) {
    try {
      const todoItem: TodoItem = { id: this.state.todos.length + 1, title };
      await db.run("INSERT INTO todos (title) VALUES (?)", [todoItem.title]);
      this.setState({ todos: [...this.state.todos, todoItem] });
    } catch (error) {
      console.error(error);
    }
  }

  async listTodos() {
    try {
      const todos = await db.all("SELECT * FROM todos");
      return todos;
    } catch (error) {
      console.error(error);
      return [];
    }
  }

  async deleteTodo(id: number) {
    try {
      await db.run("DELETE FROM todos WHERE id=?", [id]);
      this.setState({ todos: this.state.todos.filter(todo => todo.id !== id) });
    } catch (error) {
      console.error(error);
    }
  }

  render() {
    return (
      <View>
        <TodoList />
        <View>
          <Text>Todo List:</Text>
          <Button title="Add Todo" onPress={this.addTodo.bind(this)} />
          <Button title="List Todos" onPress={this.listTodos.bind(this)} />
          <Button title="Delete Todo" onPress={this.deleteTodo.bind(this, 1)} />
        </View>
      </View>
    );
  }
}

export default TodoList;

