import React from 'react';
import { FlatList } from 'react-native';
import { ItemLayoutProps } from './ItemLayout';

interface Props {
  data: any[];
}

const OptimizedFlatList = ({ data }: Props) => {
  const windowSize = 300;
  const getItemLayout = (itemIndex: number, sectionIndex: number, viewOffsetX: number, viewOffsetY: number, style?: ItemLayoutProps) => ({
    width: windowSize,
    height: windowSize,
    left: viewOffsetX + itemIndex * windowSize,
    right: viewOffsetX + (sectionIndex * windowSize),
  });

  const renderItem = ({ item }: { item: any }) => (
    <ItemLayout {...item} />
  );

  return (
    <FlatList
      data={data}
      renderItem={renderItem}
      getItemLayout={getItemLayout}
      keyExtractor={(item) => item.id.toString()}
      threshold={0.1}
      contentContainerStyle={{ flex: 1 }}
      showsVerticalScrollIndicator={false}
      showsHorizontalScrollIndicator={false}
    />
  );
};

export default OptimizedFlatList;

import { createNativeStackNavigator } from '@react-navigation/native-stack';
import HomeScreen from './screens/HomeScreen';
import DetailsScreen from './screens/DetailsScreen';

interface Props {
  navigation: any;
}

const Stack = createNativeStackNavigator<Props>;

export default function NavigationStack() {
  return (
    <Stack.Navigator>
      <Stack.Screen name="Home" component={HomeScreen} />
      <Stack.Screen name="Details" component={DetailsScreen} />
    </Stack.Navigator>
  );
}
